import { useState, useEffect, useRef } from "react";

const STORAGE_KEY = "heroedailyflow-v1";
const USER_KEY    = "heroedailyflow-user-v1";
const MONTHS_ES   = ["enero","febrero","marzo","abril","mayo","junio","julio","agosto","septiembre","octubre","noviembre","diciembre"];
const DAYS_ES     = ["domingo","lunes","martes","miércoles","jueves","viernes","sábado"];
const COLS = [
  { id:"todo",  label:"Por Hacer", col:"#4A90FF", bg:"rgba(74,144,255,0.15)", dot:"#4A90FF" },
  { id:"doing", label:"Haciendo",  col:"#FFD700", bg:"rgba(255,215,0,0.13)",  dot:"#FFD700" },
  { id:"done",  label:"Hecho",     col:"#00FF88", bg:"rgba(0,255,136,0.11)", dot:"#00CC6A" },
];
const PRIO = {
  high:   { label:"Alta",  color:"#FF4466", bg:"rgba(255,68,102,0.18)",  border:"rgba(255,68,102,0.45)"  },
  medium: { label:"Media", color:"#FFD700", bg:"rgba(255,215,0,0.14)",   border:"rgba(255,215,0,0.45)"   },
  low:    { label:"Baja",  color:"#00FF88", bg:"rgba(0,255,136,0.12)",  border:"rgba(0,255,136,0.45)"  },
};
const uid      = () => Math.random().toString(36).substr(2,9);
const todayStr = () => new Date().toISOString().split("T")[0];
const fmtDate  = s => { if(!s) return ""; const [y,m,d]=s.split("-"); return `${d}/${m}/${y}`; };
const dateES   = () => { const d=new Date(); return `${DAYS_ES[d.getDay()]}, ${d.getDate()} de ${MONTHS_ES[d.getMonth()]}`; };

const LOGO = "";
const Logo = ({ size=42 }) => (
  <img src={`data:image/png;base64,${LOGO}`} width={size} height={size}
    style={{borderRadius:"50%",objectFit:"cover",display:"block",flexShrink:0,
      boxShadow:"0 0 20px rgba(255,215,0,.5)"}}/>
);

const beep = () => {
  try {
    const ctx=new(window.AudioContext||window.webkitAudioContext)();
    [[880,0,.18],[880,.24,.18],[1100,.48,.3],[880,.84,.18],[1100,1.1,.38]].forEach(([f,s,d])=>{
      const o=ctx.createOscillator(),g=ctx.createGain();
      o.connect(g);g.connect(ctx.destination);o.frequency.value=f;
      g.gain.setValueAtTime(0,ctx.currentTime+s);
      g.gain.linearRampToValueAtTime(.5,ctx.currentTime+s+.06);
      g.gain.linearRampToValueAtTime(0,ctx.currentTime+s+d);
      o.start(ctx.currentTime+s);o.stop(ctx.currentTime+s+d+.1);
    });
  }catch(e){}
};

/* ── SPLASH ── */
const Splash = ({ onDone }) => {
  const [bar, setBar] = useState(0);
  useEffect(()=>{
    const iv=setInterval(()=>setBar(b=>{ if(b>=100){clearInterval(iv);onDone();return 100;} return b+2; }),60);
    return ()=>clearInterval(iv);
  },[]);
  return (
    <div style={{position:"fixed",inset:0,zIndex:999,background:"linear-gradient(145deg,#0A071A,#0F0C1E)",
      display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:18}}>
      <div style={{position:"relative",width:140,height:140,display:"flex",alignItems:"center",justifyContent:"center"}}>
        {[0,1,2].map(i=>(
          <div key={i} style={{position:"absolute",borderRadius:"50%",
            border:`1px solid rgba(255,215,0,${.25-i*.07})`,
            width:90+i*28,height:90+i*28,
            animation:`rp 2s ${i*.35}s ease-in-out infinite`}}/>
        ))}
        <div style={{animation:"lb 2s ease-in-out infinite"}}><Logo size={88}/></div>
      </div>
      <div style={{textAlign:"center"}}>
        <div style={{fontSize:8,color:"rgba(255,215,0,.55)",letterSpacing:"4px",fontFamily:"'Cinzel',serif",marginBottom:5}}>PROYECTO HÉROE</div>
        <div style={{fontSize:20,fontWeight:900,fontFamily:"'Cinzel',serif",
          background:"linear-gradient(135deg,#4A90FF,#A855F7)",
          WebkitBackgroundClip:"text",WebkitTextFillColor:"transparent",letterSpacing:"1px"}}>
          Héroe Daily Flow
        </div>
      </div>
      <div style={{width:180,height:3,background:"rgba(255,255,255,.1)",borderRadius:3,overflow:"hidden"}}>
        <div style={{height:"100%",width:`${bar}%`,transition:"width .1s",
          background:"linear-gradient(90deg,#4A90FF,#FFD700,#A855F7)",borderRadius:3}}/>
      </div>
      <style>{`
        @keyframes rp{0%,100%{opacity:.15;transform:scale(1)}50%{opacity:.4;transform:scale(1.05)}}
        @keyframes lb{0%,100%{transform:scale(1) translateY(0)}50%{transform:scale(1.04) translateY(-5px)}}
      `}</style>
    </div>
  );
};

/* ════════ APP ════════ */
export default function App() {
  const [splash,    setSplash]    = useState(true);
  const [userName,  setUserName]  = useState("");
  const [showName,  setShowName]  = useState(false);
  const [nameInput, setNameInput] = useState("");
  const [tasks,     setTasks]     = useState([]);
  const [modal,     setModal]     = useState(false);
  const [editTask,  setEditTask]  = useState(null);
  const [dragId,    setDragId]    = useState(null);
  const [dragOver,  setDragOver]  = useState(null);
  const [listening, setListening] = useState(false);
  const [transcript,setTranscript]= useState("");
  const [parsing,   setParsing]   = useState(false);
  const [parsed,    setParsed]    = useState(null);
  const [alarm,     setAlarm]     = useState(null);
  const [genPh,     setGenPh]     = useState(false);
  const [vErr,      setVErr]      = useState("");
  const [form, setForm] = useState({title:"",description:"",date:todayStr(),time:"",priority:"medium",tags:"",phrase:"",status:"todo"});
  const aRefs=useRef({}); const rRef=useRef(null);

  useEffect(()=>{
    (async()=>{
      try{
        const ur=await window.storage.get(USER_KEY);
        const un=ur?JSON.parse(ur.value):"";
        if(un) setUserName(un); else setShowName(true);
        const tr=await window.storage.get(STORAGE_KEY);
        if(tr) setTasks(JSON.parse(tr.value));
      }catch{ setShowName(true); }
    })();
  },[]);

  const saveName=async()=>{
    if(!nameInput.trim()) return;
    setUserName(nameInput.trim());
    try{ await window.storage.set(USER_KEY,JSON.stringify(nameInput.trim())); }catch{}
    setShowName(false);
  };
  const saveTasks=async n=>{ setTasks(n); try{ await window.storage.set(STORAGE_KEY,JSON.stringify(n)); }catch{}};
  const schedule=t=>{
    if(aRefs.current[t.id]) clearTimeout(aRefs.current[t.id]);
    if(!t.time||!t.date||t.status==="done") return;
    const dl=new Date(`${t.date}T${t.time}:00`).getTime()-Date.now();
    if(dl>0&&dl<8*24*3600*1000) aRefs.current[t.id]=setTimeout(()=>{setAlarm(t);beep();},dl);
  };
  useEffect(()=>{ tasks.forEach(schedule); return()=>Object.values(aRefs.current).forEach(clearTimeout); },[tasks]);

  const startMic=async()=>{
    setVErr("");
    if(navigator.mediaDevices?.getUserMedia){
      try{ const s=await navigator.mediaDevices.getUserMedia({audio:true}); s.getTracks().forEach(t=>t.stop()); }
      catch(e){ setVErr(e.name==="NotAllowedError"?"🔒 Permití el micrófono en tu navegador.":"Sin micrófono."); return; }
    }
    const SR=window.SpeechRecognition||window.webkitSpeechRecognition;
    if(!SR){ setVErr("Usá Chrome o Safari para voz."); return; }
    const r=new SR(); r.lang="es-ES"; r.interimResults=true;
    r.onstart=()=>{setListening(true);setTranscript("");setParsed(null);};
    r.onresult=e=>{const t=Array.from(e.results).map(x=>x[0].transcript).join("");setTranscript(t);if(e.results[e.results.length-1].isFinal)setListening(false);};
    r.onerror=ev=>{setListening(false);setVErr(ev.error==="not-allowed"?"🔒 Micrófono bloqueado.":ev.error==="no-speech"?"No se detectó voz.":"Error de micrófono.");};
    r.onend=()=>setListening(false); rRef.current=r;
    try{r.start();}catch{setListening(false);setVErr("No se pudo iniciar.");}
  };
  const stopMic=()=>{rRef.current?.stop();setListening(false);};

  const parseV=async tx=>{
    if(!tx.trim()) return; setParsing(true);
    try{
      const res=await fetch("https://api.anthropic.com/v1/messages",{method:"POST",headers:{"Content-Type":"application/json"},
        body:JSON.stringify({model:"claude-sonnet-4-20250514",max_tokens:300,
          messages:[{role:"user",content:`Tarea en español, SOLO JSON.\nTexto:"${tx}"\nHoy:${todayStr()}\n{"title":"","description":"","date":"YYYY-MM-DD","time":"HH:MM o vacío","priority":"high|medium|low"}`}]})});
      const d=await res.json();
      setParsed({id:uid(),tags:[],status:"todo",phrase:"",...JSON.parse(d.content?.[0]?.text?.trim().replace(/```json|```/g,"")||"{}")});
    }catch{setParsed({id:uid(),title:tx,description:"",date:todayStr(),time:"",priority:"medium",tags:[],status:"todo",phrase:""});}
    setParsing(false);
  };
  const confirm=()=>{if(!parsed)return;saveTasks([...tasks,parsed]);setTranscript("");setParsed(null);};
  const genPhrase=async()=>{
    setGenPh(true);
    try{
      const r=await fetch("https://api.anthropic.com/v1/messages",{method:"POST",headers:{"Content-Type":"application/json"},
        body:JSON.stringify({model:"claude-sonnet-4-20250514",max_tokens:120,messages:[{role:"user",content:`Frase motivadora 1-2 oraciones.${form.title?` Tarea:"${form.title}".`:""} Solo la frase.`}]})});
      const d=await r.json(); setForm(f=>({...f,phrase:d.content?.[0]?.text?.trim()||""}));
    }catch{} setGenPh(false);
  };

  const openAdd=(s="todo")=>{setEditTask(null);setForm({title:"",description:"",date:todayStr(),time:"",priority:"medium",tags:"",phrase:"",status:s});setModal(true);};
  const openEdit=t=>{setEditTask(t);setForm({...t,tags:t.tags?.join(", ")||""});setModal(true);};
  const save=()=>{
    if(!form.title.trim()) return;
    const t={...form,tags:form.tags?form.tags.split(",").map(s=>s.trim()).filter(Boolean):[]};
    saveTasks(editTask?tasks.map(x=>x.id===editTask.id?{...x,...t}:x):[...tasks,{...t,id:uid()}]);
    setModal(false);
  };
  const del=id=>{saveTasks(tasks.filter(t=>t.id!==id));setModal(false);};
  const move=(id,s)=>saveTasks(tasks.map(t=>t.id===id?{...t,status:s}:t));
  const done=id=>{move(id,"done");setAlarm(null);};

  const S={fontSize:9,fontWeight:700,color:"rgba(74,144,255,.8)",textTransform:"uppercase",letterSpacing:"1px",marginBottom:4,fontFamily:"'Cinzel',serif"};

  return (<>
    <style>{`
      @import url('https://fonts.googleapis.com/css2?family=Cinzel:wght@400;700;900&family=Raleway:wght@300;400;500;600;700&display=swap');
      *{margin:0;padding:0;box-sizing:border-box;}
      html,body{height:100%;overflow:hidden;background:#0F0C1E;font-family:'Raleway',sans-serif;color:#fff;}
      ::-webkit-scrollbar{width:3px;} ::-webkit-scrollbar-thumb{background:#2A1E4A;border-radius:3px;}
      input,textarea{background:rgba(255,255,255,.08);border:1.5px solid rgba(74,144,255,.3);border-radius:9px;padding:8px 11px;color:#fff;font-family:'Raleway',sans-serif;font-size:12px;outline:none;width:100%;transition:all .2s;}
      input:focus,textarea:focus{border-color:rgba(74,144,255,.7);box-shadow:0 0 0 2px rgba(74,144,255,.1);}
      textarea{resize:none;line-height:1.4;} button{cursor:pointer;font-family:'Raleway',sans-serif;}
      @keyframes fi{from{opacity:0}to{opacity:1}}
      @keyframes su{from{transform:translateY(14px);opacity:0}to{transform:translateY(0);opacity:1}}
      @keyframes pu{0%,100%{box-shadow:0 0 0 0 rgba(255,107,53,.5)}70%{box-shadow:0 0 0 10px rgba(255,107,53,0)}}
      @keyframes rn{0%,100%{transform:rotate(0)}20%{transform:rotate(-14deg)}40%{transform:rotate(14deg)}60%{transform:rotate(-8deg)}80%{transform:rotate(8deg)}}
      @keyframes gp{0%,100%{text-shadow:0 0 8px rgba(255,215,0,.3)}50%{text-shadow:0 0 22px rgba(255,215,0,.85)}}
    `}</style>

    {splash && <Splash onDone={()=>setSplash(false)}/>}

    <div style={{height:"100vh",display:"flex",flexDirection:"column",background:"linear-gradient(145deg,#0F0C1E,#130E25,#0C0A18)"}}>

      {/* HEADER */}
      <div style={{flexShrink:0,padding:"7px 12px",background:"rgba(12,8,30,.96)",backdropFilter:"blur(20px)",borderBottom:"1px solid rgba(74,144,255,.25)",display:"flex",alignItems:"center",gap:10}}>
        <div style={{display:"flex",alignItems:"center",gap:8,flexShrink:0}}>
          <Logo size={38}/>
          <div>
            <div style={{fontSize:7,fontFamily:"'Cinzel',serif",fontWeight:700,letterSpacing:"2px",color:"rgba(255,215,0,.58)",textTransform:"uppercase"}}>PROYECTO HÉROE</div>
            <div style={{fontSize:15,fontWeight:700,fontFamily:"'Cinzel',serif",background:"linear-gradient(135deg,#4A90FF,#A855F7)",WebkitBackgroundClip:"text",WebkitTextFillColor:"transparent"}}>Héroe Daily Flow</div>
          </div>
        </div>
        <div style={{flex:1,textAlign:"center"}}>
          <span style={{fontSize:10,color:"rgba(255,215,0,.55)",background:"rgba(255,215,0,.08)",borderRadius:8,padding:"3px 9px",border:"1px solid rgba(255,215,0,.15)",fontWeight:600}}>📅 {dateES()}</span>
        </div>
        <div style={{display:"flex",alignItems:"center",gap:8,flexShrink:0}}>
          {userName && <span style={{fontSize:11,color:"#FFD700",fontFamily:"'Cinzel',serif",animation:"gp 3s infinite"}}>{userName}</span>}
          <button onClick={()=>openAdd()} style={{background:"linear-gradient(135deg,#1A2EDD,#6B00FF)",color:"#FFD700",border:"1px solid rgba(255,215,0,.3)",borderRadius:9,padding:"6px 12px",fontSize:11,fontFamily:"'Cinzel',serif",fontWeight:700,letterSpacing:"1px"}}>+ Nueva</button>
        </div>
      </div>

      {/* BODY */}
      <div style={{flex:1,minHeight:0,display:"flex",flexDirection:"column",padding:"8px 10px",gap:8}}>

        {/* VOICE */}
        <div style={{flexShrink:0,background:"rgba(18,14,44,.92)",borderRadius:14,padding:"10px 12px",border:"1px solid rgba(74,144,255,.25)"}}>
          <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:8}}>
            <span style={{fontSize:11,fontWeight:700,color:"#4A90FF",textTransform:"uppercase",fontFamily:"'Cinzel',serif",letterSpacing:"1px"}}>🎙 Asistente</span>
            <span style={{fontSize:10,color:"rgba(255,255,255,.35)"}}>· Hablá o escribí</span>
          </div>
          {!parsed && (
            <div style={{position:"relative"}}>
              <textarea rows={2} placeholder={"Ej: Llamar a Juan a las 17:00 · Pagar la luz hoy"}
                value={transcript} onChange={e=>{setTranscript(e.target.value);setVErr("");}} style={{paddingRight:50}}/>
              <button onClick={listening?stopMic:startMic}
                style={{position:"absolute",right:7,top:"50%",transform:"translateY(-50%)",width:36,height:36,borderRadius:"50%",border:"none",
                  background:listening?"linear-gradient(135deg,#FF6B35,#E8651A)":"linear-gradient(135deg,#4A90FF,#6B00FF)",
                  color:"#fff",fontSize:16,display:"flex",alignItems:"center",justifyContent:"center",
                  animation:listening?"pu 1.4s infinite":""}}>
                {listening?"⏹":"🎙"}
              </button>
            </div>
          )}
          {vErr && <div style={{background:"rgba(255,215,0,.1)",border:"1px solid rgba(255,215,0,.2)",borderRadius:8,padding:"6px 10px",fontSize:11,color:"#FFD700",fontWeight:600,marginTop:6}}>⚠️ {vErr}</div>}
          {transcript && !parsed && (
            <div style={{display:"flex",gap:7,marginTop:7}}>
              <button onClick={()=>{setTranscript("");setVErr("");}} style={{flex:1,padding:"7px",background:"rgba(255,255,255,.05)",border:"1.5px solid rgba(74,144,255,.25)",borderRadius:9,color:"rgba(255,255,255,.5)",fontSize:12}}>✕</button>
              <button onClick={()=>parseV(transcript)} disabled={parsing} style={{flex:2,padding:"7px",background:"linear-gradient(135deg,#1A2EDD,#6B00FF)",border:"none",borderRadius:9,color:"#FFD700",fontSize:12,fontWeight:700,opacity:parsing?.65:1,fontFamily:"'Cinzel',serif"}}>
                {parsing?"⏳ Analizando…":"✨ CREAR CON IA"}
              </button>
            </div>
          )}
          {parsed && (
            <div style={{marginTop:7,background:"rgba(74,144,255,.1)",borderRadius:12,padding:"10px",border:"1.5px solid rgba(74,144,255,.3)",animation:"su .25s ease"}}>
              <div style={{fontWeight:700,fontSize:13,color:"#fff",marginBottom:6}}>{parsed.title}</div>
              <div style={{display:"flex",gap:5,flexWrap:"wrap",marginBottom:8}}>
                {parsed.date && <span style={{fontSize:10,background:"rgba(74,144,255,.2)",color:"#4A90FF",borderRadius:7,padding:"2px 7px",fontWeight:700}}>📅 {fmtDate(parsed.date)}</span>}
                {parsed.time && <span style={{fontSize:10,background:"rgba(255,215,0,.15)",color:"#FFD700",borderRadius:7,padding:"2px 7px",fontWeight:700}}>⏰ {parsed.time}</span>}
                <span style={{fontSize:10,background:PRIO[parsed.priority]?.bg,color:PRIO[parsed.priority]?.color,borderRadius:7,padding:"2px 7px",fontWeight:700}}>{PRIO[parsed.priority]?.label}</span>
              </div>
              <div style={{display:"flex",gap:7}}>
                <button onClick={()=>{setParsed(null);setTranscript("");}} style={{flex:1,padding:"8px",background:"rgba(255,255,255,.05)",border:"1.5px solid rgba(74,144,255,.25)",borderRadius:9,color:"rgba(255,255,255,.5)",fontSize:11}}>✕</button>
                <button onClick={confirm} style={{flex:2,padding:"8px",background:"linear-gradient(135deg,#00AA66,#007744)",border:"none",borderRadius:9,color:"#00FF88",fontSize:11,fontWeight:700,fontFamily:"'Cinzel',serif"}}>✓ AGENDAR</button>
              </div>
            </div>
          )}
          {!transcript && !parsed && !listening && (
            <div style={{display:"flex",gap:5,marginTop:7,flexWrap:"wrap"}}>
              {["Llamar a Juan 17:00","Pagar la luz hoy","Reunión mañana 9:00"].map((ex,i)=>(
                <span key={i} onClick={()=>setTranscript(ex)} style={{fontSize:10,background:"rgba(74,144,255,.12)",color:"#4A90FF",borderRadius:7,padding:"3px 9px",fontWeight:600,cursor:"pointer",border:"1px solid rgba(74,144,255,.2)"}}>
                  {ex}
                </span>
              ))}
            </div>
          )}
        </div>

        {/* KANBAN */}
        <div style={{flex:1,minHeight:0,display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:8}}>
          {COLS.map(col=>{
            const ct=tasks.filter(t=>t.status===col.id);
            const iDO=dragOver===col.id;
            return (
              <div key={col.id} style={{display:"flex",flexDirection:"column",borderRadius:14,background:col.bg,
                border:`1.5px solid ${iDO?col.col:"rgba(255,255,255,.08)"}`,overflow:"hidden",
                boxShadow:iDO?`0 0 0 2px ${col.col}55`:"none",transition:"all .18s"}}
                onDragOver={e=>{ e.preventDefault();setDragOver(col.id);}}
                onDrop={e=>{ e.preventDefault();if(dragId)move(dragId,col.id);setDragId(null);setDragOver(null);}}
                onDragLeave={()=>setDragOver(null)}>
                <div style={{flexShrink:0,padding:"8px 10px",display:"flex",alignItems:"center",gap:7,borderBottom:"1px solid rgba(255,255,255,.07)"}}>
                  <div style={{width:7,height:7,borderRadius:"50%",background:col.col,boxShadow:`0 0 7px ${col.col}`}}/>
                  <div style={{flex:1,fontSize:10,fontWeight:800,textTransform:"uppercase",letterSpacing:".8px",color:col.dot,fontFamily:"'Cinzel',serif"}}>{col.label}</div>
                  <div style={{fontSize:11,fontWeight:800,background:"rgba(255,255,255,.08)",borderRadius:6,padding:"1px 7px",color:col.dot}}>{ct.length}</div>
                </div>
                <div style={{flex:1,overflowY:"auto",padding:"7px",display:"flex",flexDirection:"column",gap:6}}>
                  {ct.length===0 && <div style={{textAlign:"center",padding:"12px 0",color:`${col.col}55`,fontSize:11,fontStyle:"italic"}}>Sin tareas</div>}
                  {ct.map(t=>(
                    <div key={t.id} draggable
                      onDragStart={e=>{setDragId(t.id);e.dataTransfer.effectAllowed="move";}}
                      onDragEnd={()=>{setDragId(null);setDragOver(null);}}
                      style={{background:"rgba(20,16,50,.92)",borderRadius:11,padding:"9px 10px",
                        border:"1px solid rgba(255,255,255,.07)",borderLeft:`3px solid ${col.col}`,
                        cursor:"grab",opacity:dragId===t.id?.35:1,transition:"all .15s",userSelect:"none"}}>
                      <span style={{fontSize:9,fontWeight:800,borderRadius:5,padding:"2px 6px",
                        background:PRIO[t.priority]?.bg,color:PRIO[t.priority]?.color,
                        border:`1px solid ${PRIO[t.priority]?.border}`}}>{PRIO[t.priority]?.label}</span>
                      <div onClick={()=>openEdit(t)} style={{fontWeight:700,fontSize:12,color:"#fff",margin:"5px 0 3px",cursor:"pointer",lineHeight:1.3}}>{t.title}</div>
                      {t.description && <div style={{fontSize:10,color:"rgba(255,255,255,.5)",marginBottom:3,lineHeight:1.3,display:"-webkit-box",WebkitLineClamp:2,WebkitBoxOrient:"vertical",overflow:"hidden"}}>{t.description}</div>}
                      {t.phrase && <div style={{fontSize:9,fontStyle:"italic",color:`${col.dot}AA`,marginBottom:4,borderLeft:`2px solid ${col.col}45`,paddingLeft:6,lineHeight:1.3,display:"-webkit-box",WebkitLineClamp:2,WebkitBoxOrient:"vertical",overflow:"hidden"}}>{t.phrase}</div>}
                      {t.date && <div style={{fontSize:10,color:"rgba(255,255,255,.38)",fontWeight:600}}>📅 {fmtDate(t.date)}{t.time&&` ⏰ ${t.time}`}</div>}
                    </div>
                  ))}
                  <button onClick={()=>openAdd(col.id)} style={{marginTop:"auto",padding:"6px",background:"transparent",border:`1.5px dashed ${col.col}35`,borderRadius:9,color:`${col.col}55`,fontSize:11,fontWeight:700,transition:"all .15s"}}>
                    + Agregar
                  </button>
                </div>
              </div>
            );
          })}
        </div>

        <div style={{flexShrink:0,textAlign:"center",fontSize:8,color:"rgba(255,255,255,.14)",letterSpacing:".8px",textTransform:"uppercase"}}>
          © Jorge Lami · Proyecto Héroe ® {new Date().getFullYear()}
        </div>
      </div>
    </div>

    {/* MODAL TAREA */}
    {modal && (
      <div style={{position:"fixed",inset:0,background:"rgba(0,0,15,.85)",backdropFilter:"blur(14px)",zIndex:200,display:"flex",alignItems:"center",justifyContent:"center",padding:12,animation:"fi .2s ease"}}
        onClick={e=>e.target===e.currentTarget&&setModal(false)}>
        <div style={{background:"rgba(12,8,32,.98)",border:"1px solid rgba(74,144,255,.3)",borderRadius:18,width:"100%",maxWidth:430,maxHeight:"90vh",overflowY:"auto",animation:"su .2s ease"}}>
          <div style={{padding:"16px 16px 0",display:"flex",alignItems:"center",justifyContent:"space-between"}}>
            <div style={{fontSize:15,fontWeight:800,color:"#fff",fontFamily:"'Cinzel',serif"}}>{editTask?"Editar":"Nueva tarea"}</div>
            <button onClick={()=>setModal(false)} style={{background:"rgba(255,255,255,.08)",border:"none",borderRadius:8,width:28,height:28,fontSize:14,color:"rgba(255,255,255,.6)"}}>✕</button>
          </div>
          <div style={{padding:"12px 16px 16px",display:"flex",flexDirection:"column",gap:10}}>
            <div><div style={S}>Título *</div><input placeholder="¿Qué necesitás?" value={form.title} autoFocus onChange={e=>setForm(f=>({...f,title:e.target.value}))}/></div>
            <div><div style={S}>Descripción</div><textarea rows={2} placeholder="Detalles…" value={form.description} onChange={e=>setForm(f=>({...f,description:e.target.value}))}/></div>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:9}}>
              <div><div style={S}>Fecha</div><input type="date" value={form.date} style={{colorScheme:"dark"}} onChange={e=>setForm(f=>({...f,date:e.target.value}))}/></div>
              <div><div style={S}>⏰ Hora exacta</div><input type="time" value={form.time} style={{colorScheme:"dark"}} onChange={e=>setForm(f=>({...f,time:e.target.value}))}/></div>
            </div>
            {form.time && <div style={{background:"rgba(255,215,0,.1)",border:"1px solid rgba(255,215,0,.2)",borderRadius:9,padding:"6px 10px",fontSize:11,color:"#FFD700",fontWeight:600}}>🔔 Alarma exacta a las {form.time}</div>}
            <div><div style={S}>Prioridad</div>
              <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:6}}>
                {Object.entries(PRIO).map(([k,v])=>(
                  <button key={k} onClick={()=>setForm(f=>({...f,priority:k}))} style={{padding:"7px",borderRadius:9,fontWeight:700,fontSize:12,transition:"all .15s",border:`1.5px solid ${form.priority===k?v.color:"rgba(74,144,255,.18)"}`,background:form.priority===k?v.bg:"rgba(255,255,255,.04)",color:form.priority===k?v.color:"rgba(255,255,255,.4)"}}>{v.label}</button>
                ))}
              </div>
            </div>
            <div><div style={S}>Columna</div>
              <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:6}}>
                {COLS.map(col=>(
                  <button key={col.id} onClick={()=>setForm(f=>({...f,status:col.id}))} style={{padding:"7px",borderRadius:9,fontWeight:700,fontSize:10,transition:"all .15s",border:`1.5px solid ${form.status===col.id?col.col:"rgba(74,144,255,.18)"}`,background:form.status===col.id?`${col.col}18`:"rgba(255,255,255,.04)",color:form.status===col.id?col.dot:"rgba(255,255,255,.4)"}}>{col.label}</button>
                ))}
              </div>
            </div>
            <div><div style={S}>Etiquetas (coma)</div><input placeholder="trabajo, urgente…" value={form.tags} onChange={e=>setForm(f=>({...f,tags:e.target.value}))}/></div>
            <div><div style={S}>Frase motivadora</div>
              <div style={{position:"relative"}}>
                <textarea rows={2} placeholder="Escribí o generá con IA…" value={form.phrase} style={{paddingRight:66}} onChange={e=>setForm(f=>({...f,phrase:e.target.value}))}/>
                <button onClick={genPhrase} disabled={genPh} style={{position:"absolute",right:6,top:6,background:"linear-gradient(135deg,#1A2EDD,#6B00FF)",border:"none",borderRadius:7,padding:"4px 8px",color:"#FFD700",fontSize:10,fontWeight:700,opacity:genPh?.5:1,fontFamily:"'Cinzel',serif"}}>
                  {genPh?"⏳":"✨"} IA
                </button>
              </div>
            </div>
            <div style={{display:"flex",gap:8,marginTop:2}}>
              {editTask && <button onClick={()=>del(editTask.id)} style={{background:"rgba(255,68,102,.15)",color:"#FF4466",border:"1.5px solid rgba(255,68,102,.35)",borderRadius:11,padding:"10px 11px",fontSize:14}}>🗑</button>}
              <button onClick={save} disabled={!form.title.trim()} style={{flex:1,background:"linear-gradient(135deg,#1A2EDD,#6B00FF)",color:"#FFD700",border:"1px solid rgba(255,215,0,.3)",borderRadius:13,padding:11,fontSize:13,fontWeight:800,opacity:form.title.trim()?1:.45,fontFamily:"'Cinzel',serif",letterSpacing:"1px"}}>
                {editTask?"GUARDAR":"CREAR TAREA"}
              </button>
            </div>
          </div>
        </div>
      </div>
    )}

    {/* ALARMA */}
    {alarm && (
      <div style={{position:"fixed",inset:0,background:"rgba(0,0,15,.9)",backdropFilter:"blur(16px)",zIndex:300,display:"flex",alignItems:"center",justifyContent:"center",padding:16,animation:"fi .2s ease"}}>
        <div style={{background:"rgba(12,8,32,.98)",border:"2px solid rgba(255,215,0,.4)",borderRadius:22,padding:"24px 20px",maxWidth:310,width:"100%",textAlign:"center",animation:"su .28s ease"}}>
          <div style={{fontSize:48,marginBottom:4,display:"inline-block",animation:"rn 1s ease infinite"}}>🔔</div>
          <div style={{fontSize:9,fontWeight:700,color:"#FFD700",letterSpacing:"2px",textTransform:"uppercase",marginBottom:3,fontFamily:"'Cinzel',serif"}}>¡HORA DE TU TAREA!</div>
          {alarm.time && <div style={{fontSize:26,fontWeight:900,color:"#4A90FF",marginBottom:4,fontFamily:"'Cinzel',serif"}}>⏱ {alarm.time}</div>}
          <div style={{fontSize:17,fontWeight:800,color:"#fff",marginBottom:5,lineHeight:1.3}}>{alarm.title}</div>
          {alarm.description && <div style={{fontSize:12,color:"rgba(255,255,255,.55)",marginBottom:8,lineHeight:1.4}}>{alarm.description}</div>}
          {alarm.phrase && <div style={{fontSize:11,fontStyle:"italic",color:"rgba(255,215,0,.65)",marginBottom:12,borderLeft:"2px solid rgba(255,215,0,.28)",paddingLeft:9,textAlign:"left",lineHeight:1.4}}>{alarm.phrase}</div>}
          <div style={{display:"flex",gap:9}}>
            <button onClick={()=>{setAlarm(null);setTimeout(()=>{setAlarm(alarm);beep();},5*60*1000);}} style={{flex:1,padding:"10px",background:"rgba(255,255,255,.07)",border:"1.5px solid rgba(74,144,255,.28)",borderRadius:13,color:"rgba(255,255,255,.7)",fontWeight:700,fontSize:13}}>😴 5 min</button>
            <button onClick={()=>done(alarm.id)} style={{flex:1,padding:"10px",background:"linear-gradient(135deg,#00AA66,#007744)",border:"none",borderRadius:13,color:"#00FF88",fontWeight:800,fontSize:14,fontFamily:"'Cinzel',serif",letterSpacing:"1px"}}>✓ ¡HECHO!</button>
          </div>
        </div>
      </div>
    )}

    {/* NOMBRE — primer ingreso */}
    {showName && (
      <div style={{position:"fixed",inset:0,background:"rgba(0,0,15,.93)",backdropFilter:"blur(16px)",zIndex:400,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",padding:"24px",animation:"fi .4s ease"}}>
        <div style={{filter:"drop-shadow(0 0 16px rgba(255,215,0,.45))",marginBottom:12}}><Logo size={72}/></div>
        <div style={{fontFamily:"'Cinzel',serif",fontSize:8,color:"rgba(255,215,0,.55)",letterSpacing:"4px",textTransform:"uppercase",marginBottom:4}}>PROYECTO HÉROE</div>
        <div style={{fontFamily:"'Cinzel',serif",fontSize:20,fontWeight:900,background:"linear-gradient(135deg,#4A90FF,#A855F7)",WebkitBackgroundClip:"text",WebkitTextFillColor:"transparent",marginBottom:5,letterSpacing:"1px"}}>Héroe Daily Flow</div>
        <div style={{width:50,height:1.5,background:"linear-gradient(90deg,transparent,#FFD700,transparent)",marginBottom:18}}/>
        <div style={{fontSize:13,color:"rgba(255,255,255,.72)",textAlign:"center",marginBottom:16,lineHeight:1.7,fontWeight:300,maxWidth:260}}>
          Bienvenido.<br/><span style={{color:"#FFD700",fontWeight:700}}>¿Cómo te llamamos?</span>
        </div>
        <input autoFocus placeholder="Tu nombre, héroe…" value={nameInput}
          onChange={e=>setNameInput(e.target.value)} onKeyDown={e=>e.key==="Enter"&&saveName()}
          style={{width:"100%",maxWidth:270,textAlign:"center",fontSize:15,fontWeight:600,marginBottom:12,
            border:`1.5px solid ${nameInput.trim()?"rgba(255,215,0,.6)":"rgba(255,215,0,.22)"}`,
            background:"rgba(255,255,255,.07)",padding:"11px 14px",borderRadius:12,color:"#fff",outline:"none"}}/>
        <button onClick={saveName} disabled={!nameInput.trim()} style={{
          background:nameInput.trim()?"linear-gradient(135deg,#1A2EDD,#6B00FF)":"rgba(255,255,255,.07)",
          color:nameInput.trim()?"#FFD700":"rgba(255,255,255,.22)",
          border:`1.5px solid ${nameInput.trim()?"rgba(255,215,0,.4)":"transparent"}`,
          borderRadius:12,padding:"11px 36px",fontFamily:"'Cinzel',serif",fontSize:13,fontWeight:700,letterSpacing:"2px"}}>
          COMENZAR →
        </button>
        <div style={{marginTop:14,fontSize:8,color:"rgba(255,255,255,.14)",letterSpacing:".8px",textTransform:"uppercase",textAlign:"center"}}>
          © Jorge Lami · Proyecto Héroe ® {new Date().getFullYear()}
        </div>
      </div>
    )}
  </>);
}
